package com.bankapp;

import android.content.Context;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class BankingAppActivity extends AppCompatActivity {
    private static final String PREFS_NAME = "BankingPrefs";
    private static final String BALANCE_KEY = "account_balance";
    private static final String TRANSACTION_HISTORY_KEY = "transaction_history";
    
    private TextView balanceTextView;
    private Button depositButton;
    private Button withdrawButton;
    private Button checkBalanceButton;
    
    private SharedPreferences sharedPreferences;
    private ExecutorService executorService;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking_app);
        
        initializeViews();
        setupClickListeners();
        setupSharedPreferences();
        setupExecutorService();
        updateBalanceDisplay();
    }
    
    private void initializeViews() {
        balanceTextView = findViewById(R.id.balanceTextView);
        depositButton = findViewById(R.id.depositButton);
        withdrawButton = findViewById(R.id.withdrawButton);
        checkBalanceButton = findViewById(R.id.checkBalanceButton);
    }
    
    private void setupClickListeners() {
        depositButton.setOnClickListener(v -> performTransaction(true, 100.0));
        withdrawButton.setOnClickListener(v -> performTransaction(false, 50.0));
        checkBalanceButton.setOnClickListener(v -> updateBalanceDisplay());
    }
    
    private void setupSharedPreferences() {
        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
    }
    
    private void setupExecutorService() {
        executorService = Executors.newSingleThreadExecutor();
    }
    
    private void performTransaction(boolean isDeposit, double amount) {
        executorService.execute(() -> {
            try {
                BigDecimal currentBalance = new BigDecimal(getStoredBalance());
                BigDecimal transactionAmount = new BigDecimal(String.valueOf(amount));
                
                BigDecimal newBalance;
                if (isDeposit) {
                    newBalance = currentBalance.add(transactionAmount);
                    saveTransaction("DEPOSIT", amount);
                } else {
                    if (currentBalance.compareTo(transactionAmount) < 0) {
                        runOnUiThread(() -> Toast.makeText(this, "Insufficient funds", Toast.LENGTH_SHORT).show());
                        return;
                    }
                    newBalance = currentBalance.subtract(transactionAmount);
                    saveTransaction("WITHDRAWAL", amount);
                }
                
                saveBalance(newBalance.toString());
                runOnUiThread(() -> {
                    updateBalanceDisplay();
                    Toast.makeText(this, 
                        isDeposit ? "Deposit successful" : "Withdrawal successful", 
                        Toast.LENGTH_SHORT).show();
                });
            } catch (Exception e) {
                runOnUiThread(() -> Toast.makeText(this, "Transaction failed", Toast.LENGTH_SHORT).show());
            }
        });
    }
    
    private void saveBalance(String balance) {
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putString(BALANCE_KEY, balance);
        editor.apply();
    }
    
    private String getStoredBalance() {
        return sharedPreferences.getString(BALANCE_KEY, "0.00");
    }
    
    private void saveTransaction(String type, double amount) {
        String history = sharedPreferences.getString(TRANSACTION_HISTORY_KEY, "");
        String newEntry = String.format("%s: %s $%.2f\n", 
            getCurrentTimestamp(), type, amount);
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putString(TRANSACTION_HISTORY_KEY, history + newEntry);
        editor.apply();
    }
    
    private void updateBalanceDisplay() {
        executorService.execute(() -> {
            String balance = getStoredBalance();
            BigDecimal balanceDecimal = new BigDecimal(balance).setScale(2, RoundingMode.HALF_UP);
            runOnUiThread(() -> balanceTextView.setText(String.format("Balance: $%.2f", balanceDecimal)));
        });
    }
    
    private String getCurrentTimestamp() {
        return java.text.DateFormat.getDateTimeInstance().format(new java.util.Date());
    }
    
    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (executorService != null) {
            executorService.shutdown();
        }
    }
}